// === GEMINI FALLBACK AUTOMÁTICO ===
// Tenta modelos em ordem até um funcionar
// Se todos falharem, lança erro com detalhes

const GEMINI_KEY = 'AIzaSyA9Gh9JYW4VEiKVlmCR0ziUD3umK9pJYWQ';
const MODELOS = ["gemini-2.5-flash", "gemini-2.5-flash-lite", "gemini-2.5-pro"];
const TELEGRAM_TOKEN = '8603024374:AAH81RHxIBwOsTaDI87nM7ap2DHcuE3xnxA';
const TELEGRAM_CHAT = '8397602236';

const promptCompleto = $json.prompt_completo;
const temperature = 0.2;
const maxTokens = 8192;

async function chamarGemini(modelo, prompt, temp, tokens) {
  const url = `https://generativelanguage.googleapis.com/v1beta/models/${modelo}:generateContent?key=${GEMINI_KEY}`;
  const body = JSON.stringify({
    contents: [{parts: [{text: prompt}]}],
    generationConfig: {temperature: temp, maxOutputTokens: tokens}
  });

  const resp = await fetch(url, {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: body,
    signal: AbortSignal.timeout(120000)
  });

  const data = await resp.json();

  if (data.error) {
    const code = data.error.code || resp.status;
    throw new Error(`${code}: ${data.error.message}`);
  }

  if (!data.candidates || data.candidates.length === 0) {
    throw new Error('Resposta vazia');
  }

  if (data.candidates[0].finishReason === 'SAFETY') {
    throw new Error('Bloqueado por filtro de segurança');
  }

  return data;
}

async function notificarTelegram(msg) {
  try {
    await fetch(`https://api.telegram.org/bot${TELEGRAM_TOKEN}/sendMessage`, {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({chat_id: TELEGRAM_CHAT, text: msg})
    });
  } catch(e) {}
}

let resultado = null;
let modeloUsado = '';
const erros = [];

for (const modelo of MODELOS) {
  try {
    resultado = await chamarGemini(modelo, promptCompleto, temperature, maxTokens);
    modeloUsado = modelo;
    break;
  } catch (e) {
    erros.push(`${modelo}: ${e.message}`);
    if (e.message.includes('429') || e.message.includes('RESOURCE_EXHAUSTED') || e.message.includes('quota')) {
      await notificarTelegram(`⚠️ Gemini ${modelo} sem quota. Tentando próximo...`);
      continue;
    }
    // Erro não relacionado a quota — tentar próximo mesmo assim
    continue;
  }
}

if (!resultado) {
  await notificarTelegram(`❌ TODOS os modelos Gemini falharam:\n${erros.join('\n')}`);
  throw new Error('Todos os modelos falharam: ' + erros.join(' | '));
}

// Se usou modelo diferente do primeiro, notificar
if (modeloUsado !== MODELOS[0]) {
  await notificarTelegram(`🔄 Modelo trocado: ${modeloUsado} (primário indisponível)`);
}

const texto = resultado.candidates[0].content.parts[0].text;

return [{
  json: {
    ...($input.all()[0].json),
    gemini_response: resultado,
    gemini_text: texto,
    modelo_usado: modeloUsado,
    fallback: modeloUsado !== MODELOS[0]
  }
}];

// Texto já extraído pelo nó de fallback
const sintese = $input.all()[0].json.gemini_text;
const modeloUsado = $input.all()[0].json.modelo_usado || 'desconhecido';

// Extrair dados b\u00e1sicos via regex
const cnj = $('Validar Input').first().json.cnj;
const vocativo = $('Validar Input').first().json.vocativo;
const genero = $('Validar Input').first().json.genero_juiz;

// Extrair vara e comarca
const varaMatch = sintese.match(/Vara\s+e\s+comarca\s*\|\s*(.+?)(?:\n|\|)/i);
const vara = varaMatch ? varaMatch[1].trim() : '[VERIFICAR VARA]';

// Extrair valor da causa
const valorMatch = sintese.match(/Valor\s+da\s+causa\s*\|\s*R?\$?\s*([\d.,]+)/i);
const valorCausa = valorMatch ? valorMatch[1].trim() : '[VERIFICAR]';

// Extrair tipo de a\u00e7\u00e3o
const tipoMatch = sintese.match(/Tipo\s+de\s+a\u00e7\u00e3o\s*\|\s*(.+?)(?:\n|\|)/i);
const tipoAcao = tipoMatch ? tipoMatch[1].trim() : '[VERIFICAR]';

// Extrair quesitos total
const quesitosMatch = sintese.match(/\*\*TOTAL\*\*\s*\|\s*\*\*(\d+)\*\*/i);
const totalQuesitos = quesitosMatch ? quesitosMatch[1] : '[VERIFICAR]';

// Data atual por extenso
const meses = ['janeiro','fevereiro','mar\u00e7o','abril','maio','junho','julho','agosto','setembro','outubro','novembro','dezembro'];
const hoje = new Date();
const dataExtenso = hoje.getDate() + ' de ' + meses[hoje.getMonth()] + ' de ' + hoje.getFullYear();

// Montar peti\u00e7\u00e3o de aceite
const peticao = 'AO JU\u00cdZO DA ' + vara + ' \u2013 MG\n\nProcesso n\u00ba: **' + cnj + '**\n\n**MANIFESTA\u00c7\u00c3O \u2013 ACEITE DE ENCARGO E HONOR\u00c1RIOS**\n\n**' + vocativo + '**,\n\nEm aten\u00e7\u00e3o ao documento de **ID [VERIFICAR ID NO PJe]**, venho ratificar meu aceite dos encargos e honor\u00e1rios periciais, j\u00e1 fixados em R$ [VERIFICAR VALOR] ([VERIFICAR VALOR POR EXTENSO]).\n\nAguardo os tr\u00e2mites necess\u00e1rios para prosseguir com o agendamento da per\u00edcia m\u00e9dica, caso n\u00e3o haja suspei\u00e7\u00e3o ou impedimento sobre minha atua\u00e7\u00e3o.\n\nTermos em que,\nPede deferimento.\n\nDr. J\u00e9sus Eduardo Nol\u00eato da Penha\nM\u00e9dico \u2013 Perito Judicial \u2013 CRM-MG 92.148\nMembro da ABMLPM \u2013 Associa\u00e7\u00e3o Brasileira de Medicina Legal e Per\u00edcia M\u00e9dica\n\n' + dataExtenso + ',\nGovernador Valadares \u2013 MG.';

// Campos pendentes
const camposPendentes = [];
const matches = peticao.match(/\[VERIFICAR[^\]]*\]/g);
if (matches) camposPendentes.push(...matches);

return [{
  json: {
    cnj,
    vara,
    tipo_acao: tipoAcao,
    valor_causa: valorCausa,
    total_quesitos: totalQuesitos,
    peticao_md: peticao,
    sintese_completa: sintese,
    campos_pendentes: camposPendentes,
    data: dataExtenso
  }
}];
